SELECT created_by
FROM reports
WHERE created_date = (SELECT MAX(created_date) FROM reports);

SELECT model_name
FROM models
WHERE status = 'active' AND auc > (SELECT AVG(auc) FROM models);

SELECT dataset_name
  FROM datasets
  WHERE dataset_id IN (
    SELECT dataset_id
    FROM dataset_versions
  );

SELECT model_name 
FROM models 
ORDER BY model_name;
